module RefModule(
	input clock_i,
	input D,
	input S,
	input R,
	output Q
);reg out;	// Need to reset before use, default is powerup high

	assign Q = out;

	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clock_i or posedge dbg_halt)
	begin
		if( S ) 
			out <= 1'b1;
		else if( R )
			out <= 1'b0;
		else
			out <= D;
	end
endmodule
